#include <bits/stdc++.h>
using namespace std;
int a[105][105],s[105][105],ha,l=1;
int main(){
	int n,m;
	cin>>n>>m;
	for(int i=1;i<=n;i++){
		for(int j=1;j<=m;j++){
			cin>>a[i][j];
			s[i][j]=s[i][j-1]+s[i-1][j]-s[i-1][j-1]+a[i][j];
		}
	}
	for(;l<=min(n,m);){
		for(int i=l;i<=n;i++){
			for(int j=1;j<=m;j++){
				if(s[i][j]-s[i-l][j]-s[i][j-l]+s[i-l][j-l]==l*l){
					ha=max(ha,l);
				}
			}
		}
		l++;
	}
	cout<<ha;
	return 0;
}
